product_name = #{productName}, product_type = #{productType}, reference_id = #{referenceId}, description = #{description}, cover_image = #{coverImage}, price = #{price}, original_price = #{originalPrice}, is_hot = #{isHot}, is_new = #{isNew}, is_recommended = #{isRecommended}, sort_order = #{sortOrder}, status = #{status}, stock = #{stock}, sales_count = #{salesCount}, updated_at = NOW()
WHERE id = #{id}

